#include "sd_spi.h"

#include "sd_card_pins.h"

#include "hardware/clocks.h"
#include "hardware/gpio.h"
#include "hardware/pio.h"
#include "pico/stdlib.h"
#include "pico/time.h"

#include "sd_spi.pio.h"   /* generated by pico_generate_pio_header() */

#include <stdio.h>
#include <string.h>

/* Verbose per-step logging during sd_init().  Useful for breadboard
 * bring-up where init keeps failing and we need to see whether MISO is
 * floating (0xFF), shorted low (0x00), or returning garbage.  Cheap —
 * runs only once at boot. */
#ifndef MICRONES_SD_INIT_DEBUG
#define MICRONES_SD_INIT_DEBUG 1
#endif

/* Diagnostic snapshot of the most recent sd_init() attempt.  Captured
 * unconditionally so a periodic logger (see sd_print_init_diag) can
 * replay the state long after the boot-time printf has scrolled away. */
typedef struct {
    bool     attempted;
    uint8_t  warmup[10];      /* MISO bytes during the 10-byte CS-high warmup */
    int      cmd0_attempts;   /* 0..8 */
    uint8_t  cmd0_responses[8];
    SdResult last_result;
} SdInitDiag;

static SdInitDiag s_diag;

/* SD-over-SPI command set (subset). */
enum {
    CMD0  = 0,   /* GO_IDLE_STATE */
    CMD8  = 8,   /* SEND_IF_COND */
    CMD9  = 9,   /* SEND_CSD */
    CMD12 = 12,  /* STOP_TRANSMISSION */
    CMD13 = 13,  /* SEND_STATUS */
    CMD16 = 16,  /* SET_BLOCKLEN */
    CMD17 = 17,  /* READ_SINGLE_BLOCK */
    CMD18 = 18,  /* READ_MULTIPLE_BLOCK */
    CMD24 = 24,  /* WRITE_BLOCK */
    CMD25 = 25,  /* WRITE_MULTIPLE_BLOCK */
    CMD55 = 55,  /* APP_CMD */
    CMD58 = 58,  /* READ_OCR */
    ACMD41 = 41, /* SD_SEND_OP_COND */
};

#define DATA_TOKEN_BLOCK_READ_WRITE  0xFEu
#define DATA_RESPONSE_MASK           0x1Fu
#define DATA_RESPONSE_ACCEPTED       0x05u

#define R1_IDLE          0x01u
#define R1_ILLEGAL_CMD   0x04u

static PIO sd_pio_block(void) {
#if defined(pio2) || (MICRONES_SD_PIO_INDEX > 1u)
    if (MICRONES_SD_PIO_INDEX == 2u) return pio2;
#endif
    return MICRONES_SD_PIO_INDEX == 0u ? pio0 : pio1;
}

typedef struct {
    bool        initialized;
    SdCardType  type;
    uint32_t    block_count;

    /* PIO-SPI state. */
    uint        sm;
    uint        program_offset;
    bool        program_loaded;
    bool        sm_claimed;
} SdState;

static SdState s_sd = { .sm = 0, .program_offset = 0 };

static inline void cs_assert(void)   { gpio_put(MICRONES_SD_PIN_CS, 0); }
static inline void cs_deassert(void) { gpio_put(MICRONES_SD_PIN_CS, 1); }

/* Compute the PIO clock divider for a target SCK frequency.  The PIO
 * program emits one bit per 4 cycles, so f_pio = 4 * f_sck and
 * clkdiv = f_sys / f_pio. */
static float pio_clkdiv_for_sck(uint32_t sck_hz) {
    if (sck_hz == 0u) sck_hz = 1u;
    uint32_t sys_hz = clock_get_hz(clk_sys);
    float div = (float)sys_hz / (float)(4u * sck_hz);
    if (div < 1.0f)        div = 1.0f;
    if (div > 65535.0f)    div = 65535.0f;
    return div;
}

static void pio_spi_apply_clkdiv(uint32_t sck_hz) {
    PIO pio = sd_pio_block();
    pio_sm_set_clkdiv(pio, s_sd.sm, pio_clkdiv_for_sck(sck_hz));
    pio_sm_clkdiv_restart(pio, s_sd.sm);
}

/* Configure side-set/out/in pins, shift directions, and pin directions.
 * Side-set is SCK; OUT writes MOSI; IN reads MISO. */
static void pio_spi_configure(PIO pio, uint sm, uint offset, float clkdiv) {
    pio_sm_config c = sd_spi_cpha0_program_get_default_config(offset);

    sm_config_set_sideset_pins(&c, MICRONES_SD_PIN_SCK);
    sm_config_set_out_pins(&c, MICRONES_SD_PIN_MOSI, 1);
    sm_config_set_in_pins(&c, MICRONES_SD_PIN_MISO);

    /* shift_right=false → MSB first.  Autopull/push at byte boundary. */
    sm_config_set_out_shift(&c, false, true, 8);
    sm_config_set_in_shift(&c,  false, true, 8);
    sm_config_set_clkdiv(&c, clkdiv);

    pio_gpio_init(pio, MICRONES_SD_PIN_SCK);
    pio_gpio_init(pio, MICRONES_SD_PIN_MOSI);
    pio_gpio_init(pio, MICRONES_SD_PIN_MISO);

    pio_sm_set_consecutive_pindirs(pio, sm, MICRONES_SD_PIN_SCK,  1, true);
    pio_sm_set_consecutive_pindirs(pio, sm, MICRONES_SD_PIN_MOSI, 1, true);
    pio_sm_set_consecutive_pindirs(pio, sm, MICRONES_SD_PIN_MISO, 1, false);

    /* MISO floats when no card is asserting it; rely on the SD card's
     * internal pullup or the host pullup (most breakouts include 47k). */
    gpio_pull_up(MICRONES_SD_PIN_MISO);

    pio_sm_init(pio, sm, offset, &c);
    pio_sm_set_enabled(pio, sm, true);
}

static uint8_t spi_xfer(uint8_t v) {
    PIO pio = sd_pio_block();
    /* Byte must be in the high 8 bits because the OSR shifts left and the
     * autopull threshold is 8.  RX comes back in the low 8 bits because
     * the ISR shifts left too — first received bit ends up at bit 7. */
    pio_sm_put_blocking(pio, s_sd.sm, ((uint32_t)v) << 24);
    return (uint8_t)pio_sm_get_blocking(pio, s_sd.sm);
}

static void spi_send_dummy(size_t count) {
    for (size_t i = 0; i < count; ++i) {
        (void)spi_xfer(0xFFu);
    }
}

/* Wait for the card to release the bus (MISO high) for up to timeout_ms. */
static bool wait_not_busy(uint32_t timeout_ms) {
    absolute_time_t deadline = make_timeout_time_ms(timeout_ms);
    while (!time_reached(deadline)) {
        if (spi_xfer(0xFFu) == 0xFFu) {
            return true;
        }
    }
    return false;
}

/* Standard CRC7 used by CMD0 / CMD8 / CMD58. */
static uint8_t crc7(const uint8_t *data, size_t len) {
    uint8_t crc = 0;
    for (size_t i = 0; i < len; ++i) {
        crc ^= data[i];
        for (int b = 0; b < 8; ++b) {
            crc = (uint8_t)((crc & 0x80u) ? (uint8_t)((crc << 1) ^ 0x09u) : (uint8_t)(crc << 1));
        }
    }
    return (uint8_t)((crc << 1) | 0x01u);
}

static uint8_t send_cmd(uint8_t cmd, uint32_t arg) {
    uint8_t buf[6];
    buf[0] = (uint8_t)(0x40u | (cmd & 0x3Fu));
    buf[1] = (uint8_t)((arg >> 24) & 0xFFu);
    buf[2] = (uint8_t)((arg >> 16) & 0xFFu);
    buf[3] = (uint8_t)((arg >> 8) & 0xFFu);
    buf[4] = (uint8_t)(arg & 0xFFu);
    buf[5] = crc7(buf, 5);

    /* Allow the card to release bus before issuing the next command. */
    (void)wait_not_busy(500);

    for (int i = 0; i < 6; ++i) {
        (void)spi_xfer(buf[i]);
    }

    /* Discard the optional stuff byte after CMD12. */
    if (cmd == CMD12) {
        (void)spi_xfer(0xFFu);
    }

    /* Poll for the R1 response (high bit clear). */
    for (int i = 0; i < 16; ++i) {
        uint8_t r = spi_xfer(0xFFu);
        if ((r & 0x80u) == 0u) {
            return r;
        }
    }
    return 0xFFu;
}

static uint8_t send_acmd(uint8_t cmd, uint32_t arg) {
    (void)send_cmd(CMD55, 0);
    return send_cmd(cmd, arg);
}

static SdResult read_data_block(uint8_t *buf) {
    absolute_time_t deadline = make_timeout_time_ms(200);
    while (!time_reached(deadline)) {
        uint8_t t = spi_xfer(0xFFu);
        if (t == DATA_TOKEN_BLOCK_READ_WRITE) {
            for (int i = 0; i < 512; ++i) {
                buf[i] = spi_xfer(0xFFu);
            }
            (void)spi_xfer(0xFFu);  /* CRC hi */
            (void)spi_xfer(0xFFu);  /* CRC lo */
            return SD_OK;
        }
        if (t != 0xFFu) {
            return SD_ERR_READ;
        }
    }
    return SD_ERR_TIMEOUT;
}

bool sd_card_present(void) {
#if MICRONES_SD_CD_DISABLED
    return true;
#else
    bool level = gpio_get(MICRONES_SD_PIN_CD);
#if MICRONES_SD_CD_ACTIVE_LOW
    return !level;
#else
    return level;
#endif
#endif
}

bool       sd_is_initialized(void) { return s_sd.initialized; }
SdCardType sd_card_type(void)       { return s_sd.type; }
uint32_t   sd_block_count(void)     { return s_sd.block_count; }

static SdResult parse_csd_block_count(const uint8_t csd[16]) {
    uint8_t version = (uint8_t)(csd[0] >> 6);
    if (version == 1u) {
        uint32_t c_size = ((uint32_t)(csd[7] & 0x3Fu) << 16) |
                          ((uint32_t)csd[8] << 8) |
                          (uint32_t)csd[9];
        s_sd.block_count = (c_size + 1u) * 1024u;
        return SD_OK;
    }
    uint32_t c_size = ((uint32_t)(csd[6] & 0x03u) << 10) |
                      ((uint32_t)csd[7] << 2) |
                      ((uint32_t)csd[8] >> 6);
    uint8_t c_size_mult = (uint8_t)(((csd[9] & 0x03u) << 1) | (csd[10] >> 7));
    uint8_t read_bl_len = (uint8_t)(csd[5] & 0x0Fu);
    uint32_t blocknr = (c_size + 1u) << (c_size_mult + 2u);
    uint32_t block_len = 1u << read_bl_len;
    s_sd.block_count = blocknr * (block_len / 512u);
    return SD_OK;
}

/* Configure CS (output, idle high) and CD (input pullup) as plain GPIOs.
 * SCK / MOSI / MISO are configured by pio_spi_configure(). */
static void sd_pins_init(void) {
    gpio_init(MICRONES_SD_PIN_CS);
    gpio_set_dir(MICRONES_SD_PIN_CS, GPIO_OUT);
    gpio_put(MICRONES_SD_PIN_CS, 1);

#if !MICRONES_SD_CD_DISABLED
    gpio_init(MICRONES_SD_PIN_CD);
    gpio_set_dir(MICRONES_SD_PIN_CD, GPIO_IN);
    gpio_pull_up(MICRONES_SD_PIN_CD);
#endif
}

void sd_deinit(void) {
    PIO pio = sd_pio_block();
    if (s_sd.sm_claimed) {
        pio_sm_set_enabled(pio, s_sd.sm, false);
        pio_sm_unclaim(pio, s_sd.sm);
    }
    if (s_sd.program_loaded) {
        pio_remove_program(pio, &sd_spi_cpha0_program, s_sd.program_offset);
    }
    memset(&s_sd, 0, sizeof(s_sd));
}

SdResult sd_init(void) {
    sd_deinit();

    /* Reset the diagnostic snapshot at the start of every attempt so a
     * later sd_print_init_diag() reflects the most recent run. */
    memset(&s_diag, 0, sizeof(s_diag));
    s_diag.attempted = true;
    s_diag.last_result = SD_ERR_NOT_INITIALIZED;
    memset(s_diag.warmup, 0xFFu, sizeof(s_diag.warmup));
    memset(s_diag.cmd0_responses, 0xFFu, sizeof(s_diag.cmd0_responses));

    sd_pins_init();

    PIO pio = sd_pio_block();
    if (!pio_can_add_program(pio, &sd_spi_cpha0_program)) {
        s_diag.last_result = SD_ERR_NOT_INITIALIZED;
        return SD_ERR_NOT_INITIALIZED;
    }
    s_sd.program_offset = pio_add_program(pio, &sd_spi_cpha0_program);
    s_sd.program_loaded = true;

    int sm = pio_claim_unused_sm(pio, false);
    if (sm < 0) {
        s_diag.last_result = SD_ERR_NOT_INITIALIZED;
        sd_deinit();
        return SD_ERR_NOT_INITIALIZED;
    }
    s_sd.sm = (uint)sm;
    s_sd.sm_claimed = true;

    pio_spi_configure(pio, s_sd.sm, s_sd.program_offset,
                      pio_clkdiv_for_sck(MICRONES_SD_INIT_BAUD_HZ));

    if (!sd_card_present()) {
        s_diag.last_result = SD_ERR_NO_CARD;
        return SD_ERR_NO_CARD;
    }

    /* Power-up sequence: CS high, send 80+ clocks at < 400 kHz with MOSI
     * held high.  Each spi_xfer of 0xFF drives MOSI high for 8 clocks.
     * Capture the MISO bytes seen during the warmup — they're the cheapest
     * sanity check on the bus. */
    cs_deassert();
    sleep_ms(2);
    for (int i = 0; i < 10; ++i) {
        s_diag.warmup[i] = spi_xfer(0xFFu);
    }

    /* CMD0 must be sent with CS asserted. */
    cs_assert();
    SdResult result = SD_OK;
    bool got_idle = false;
    for (int attempt = 0; attempt < 8; ++attempt) {
        uint8_t r = send_cmd(CMD0, 0);
        if (s_diag.cmd0_attempts < (int)(sizeof(s_diag.cmd0_responses)
                                         / sizeof(s_diag.cmd0_responses[0]))) {
            s_diag.cmd0_responses[s_diag.cmd0_attempts] = r;
        }
        ++s_diag.cmd0_attempts;
        if (r == R1_IDLE) {
            got_idle = true;
            break;
        }
        sleep_ms(10);
    }
    if (!got_idle) {
        s_diag.last_result = SD_ERR_CMD0;
        result = SD_ERR_CMD0;
        goto fail;
    }

    /* CMD8: voltage check.  Argument 0x1AA = 2.7-3.6V, check pattern 0xAA. */
    uint8_t r1 = send_cmd(CMD8, 0x000001AAu);
    bool v2_card = false;
    if (r1 == R1_IDLE) {
        uint8_t echo[4];
        for (int i = 0; i < 4; ++i) echo[i] = spi_xfer(0xFFu);
        if (echo[2] == 0x01u && echo[3] == 0xAAu) {
            v2_card = true;
        } else {
            result = SD_ERR_CMD8;
            goto fail;
        }
    } else if ((r1 & R1_ILLEGAL_CMD) == 0u) {
        result = SD_ERR_CMD8;
        goto fail;
    }

    /* ACMD41: send op cond.  Poll for ready (R1 = 0). */
    absolute_time_t deadline = make_timeout_time_ms(2000);
    bool ready = false;
    while (!time_reached(deadline)) {
        uint8_t r = send_acmd(ACMD41, v2_card ? 0x40000000u : 0);
        if (r == 0u) {
            ready = true;
            break;
        }
        sleep_ms(2);
    }
    if (!ready) {
        result = SD_ERR_INIT_TIMEOUT;
        goto fail;
    }

    /* CMD58: read OCR to detect SDHC. */
    bool sdhc = false;
    if (v2_card) {
        if (send_cmd(CMD58, 0) != 0u) {
            result = SD_ERR_OCR;
            goto fail;
        }
        uint8_t ocr[4];
        for (int i = 0; i < 4; ++i) ocr[i] = spi_xfer(0xFFu);
        sdhc = (ocr[0] & 0x40u) != 0u;
    }

    if (!sdhc) {
        if (send_cmd(CMD16, 512) != 0u) {
            result = SD_ERR_OCR;
            goto fail;
        }
    }

    s_sd.type = sdhc ? SD_TYPE_SDHC : (v2_card ? SD_TYPE_SDV2 : SD_TYPE_SDV1);

    /* CMD9: SEND_CSD to learn capacity. */
    if (send_cmd(CMD9, 0) == 0u) {
        uint8_t csd[16];
        if (read_data_block(csd) == SD_OK) {
            (void)parse_csd_block_count(csd);
        }
    }

    cs_deassert();
    spi_send_dummy(1);

    /* Bump the PIO clock to the run rate now that init is past. */
    pio_spi_apply_clkdiv(MICRONES_SD_RUN_BAUD_HZ);

    s_sd.initialized = true;
    s_diag.last_result = SD_OK;
    return SD_OK;

fail:
    cs_deassert();
    spi_send_dummy(1);
    s_sd.initialized = false;
    s_diag.last_result = result;
    return result;
}

void sd_print_init_diag(void) {
    if (!s_diag.attempted) {
        printf("SD diag: sd_init() not yet called\n");
        return;
    }
    printf("SD diag: pins MISO=%u SCK=%u MOSI=%u CS=%u PIO=%u  result=%d\n",
           (unsigned)MICRONES_SD_PIN_MISO,
           (unsigned)MICRONES_SD_PIN_SCK,
           (unsigned)MICRONES_SD_PIN_MOSI,
           (unsigned)MICRONES_SD_PIN_CS,
           (unsigned)MICRONES_SD_PIO_INDEX,
           (int)s_diag.last_result);
    printf("SD diag: warmup MISO");
    for (int i = 0; i < (int)(sizeof(s_diag.warmup) / sizeof(s_diag.warmup[0])); ++i) {
        printf(" %02X", s_diag.warmup[i]);
    }
    printf("\n");
    printf("SD diag: CMD0 attempts=%d responses", s_diag.cmd0_attempts);
    int n = s_diag.cmd0_attempts;
    int cap = (int)(sizeof(s_diag.cmd0_responses) / sizeof(s_diag.cmd0_responses[0]));
    if (n > cap) n = cap;
    for (int i = 0; i < n; ++i) {
        printf(" %02X", s_diag.cmd0_responses[i]);
    }
    printf("\n");
}

static uint32_t lba_to_address(uint32_t lba) {
    return s_sd.type == SD_TYPE_SDHC ? lba : (lba * 512u);
}

SdResult sd_read_block(uint32_t lba, uint8_t *buf) {
    if (!s_sd.initialized) return SD_ERR_NOT_INITIALIZED;
    cs_assert();
    SdResult r;
    if (send_cmd(CMD17, lba_to_address(lba)) != 0u) {
        r = SD_ERR_READ;
    } else {
        r = read_data_block(buf);
    }
    cs_deassert();
    spi_send_dummy(1);
    return r;
}

SdResult sd_write_block(uint32_t lba, const uint8_t *buf) {
    if (!s_sd.initialized) return SD_ERR_NOT_INITIALIZED;
    cs_assert();
    SdResult r = SD_OK;
    if (send_cmd(CMD24, lba_to_address(lba)) != 0u) {
        r = SD_ERR_WRITE;
        goto out;
    }
    (void)spi_xfer(0xFFu);
    (void)spi_xfer(DATA_TOKEN_BLOCK_READ_WRITE);
    for (int i = 0; i < 512; ++i) {
        (void)spi_xfer(buf[i]);
    }
    /* Dummy CRC. */
    (void)spi_xfer(0xFFu);
    (void)spi_xfer(0xFFu);

    uint8_t resp = spi_xfer(0xFFu);
    if ((resp & DATA_RESPONSE_MASK) != DATA_RESPONSE_ACCEPTED) {
        r = SD_ERR_WRITE;
        goto out;
    }

    if (!wait_not_busy(500)) {
        r = SD_ERR_TIMEOUT;
    }

out:
    cs_deassert();
    spi_send_dummy(1);
    return r;
}
